import { axios, store } from './config/axios-config'

const getIESIndicadores = async ({anoSelecionado, estadoSelecionado, municipioSelecionado, cursoSelecionado, instituicaoSelecionada}) => {


    if(anoSelecionado !== '' && estadoSelecionado !== ''){
        
        // Bug do Redux. Tem que adicionar esse setTimeout pra funcionar
        setTimeout(() =>{store.dispatch({ type: 'SET_LOADING', loading: true })}, 0)
        
        
        try {
            const response = await axios.post('/getIESIndicadores', {
                ano: anoSelecionado,
                uf: estadoSelecionado,
                municipio: municipioSelecionado,
                curso: cursoSelecionado,
                ies: instituicaoSelecionada
            })

            store.dispatch({ type: 'SET_IES_INDICADORES', list: response.data })
        } catch (error) {
            console.log('deu erro')
        }
        
        

        
    }

}

export default getIESIndicadores