import { axios, store } from './config/axios-config'

const getIndicadoresROI = async ({salarioMedio, salarioEnsinoMedio, custo}) => {


        // Bug do Redux. Tem que adicionar esse setTimeout pra funcionar
        setTimeout(() =>{store.dispatch({ type: 'SET_LOADING', loading: true })}, 0)
        
        
        try {
            const response = await axios.post('/getIndicadoresROI', {
                salarioMedio,
                salarioEnsinoMedio,
                custo
            })

            store.dispatch({ type: 'SET_ROI', list: response.data.indicadorROI })
            
            store.dispatch({ type: 'SET_LOADING', loading: false })
        } catch (error) {
            console.log('deu erro')
        }
        

        

}

export default getIndicadoresROI