import * as actionTypes from './actions';
import initialState from './initialState'

// Responsável por alterar o menu
import getMenuItems from './menuItems'

// Funções de busca de dados
import getOcupationData from '../connection/getOcupationData'
import getIESData from '../connection/getIESData'
import getIndicadores from '../connection/getIndicadores'
import getIESIndicadores from '../connection/getIESIndicadores'
import getIndicadoresROI from '../connection/getIndicadoresROI'



const reducer = (state = initialState, action) => {
    let trigger = [];
    let open = [];

    switch (action.type) {
        case actionTypes.COLLAPSE_MENU:
            return {
                ...state,
                collapseMenu: !state.collapseMenu
            };
        case actionTypes.COLLAPSE_TOGGLE:
            if (action.menu.type === 'sub') {
                open = state.isOpen;
                trigger = state.isTrigger;

                const triggerIndex = trigger.indexOf(action.menu.id);
                if (triggerIndex > -1) {
                    open = open.filter(item => item !== action.menu.id);
                    trigger = trigger.filter(item => item !== action.menu.id);
                }

                if (triggerIndex === -1) {
                    open = [...open, action.menu.id];
                    trigger = [...trigger, action.menu.id];
                }
            } else {
                open = state.isOpen;
                const triggerIndex = (state.isTrigger).indexOf(action.menu.id);
                trigger = (triggerIndex === -1) ? [action.menu.id] : [];
                open = (triggerIndex === -1) ? [action.menu.id] : [];
            }

            return {
                ...state,
                isOpen: open,
                isTrigger: trigger
            };
        case actionTypes.NAV_CONTENT_LEAVE:
            return {
                ...state,
                isOpen: open,
                isTrigger: trigger,
            };
        case actionTypes.NAV_COLLAPSE_LEAVE:
            if (action.menu.type === 'sub') {
                open = state.isOpen;
                trigger = state.isTrigger;

                const triggerIndex = trigger.indexOf(action.menu.id);
                if (triggerIndex > -1) {
                    open = open.filter(item => item !== action.menu.id);
                    trigger = trigger.filter(item => item !== action.menu.id);
                }
                return {
                    ...state,
                    isOpen: open,
                    isTrigger: trigger,
                };
            }
            return {...state};
        case actionTypes.FULL_SCREEN :
            return {
                ...state,
                isFullScreen: !state.isFullScreen
            };
        case actionTypes.FULL_SCREEN_EXIT:
            return {
                ...state,
                isFullScreen: false
            };
        case actionTypes.CHANGE_LAYOUT:
            return {
                ...state,
                layout: action.layout
            };
        case actionTypes.SELECT_COURSE:
            // Acrescenta os dados do curso selecionado no Redux
            getOcupationData(action.title)
            // Acrescenta a lista de IES no Redux
            getIESData(action.title)
            
            return {
                ...state,
                cursoSelecionado: action.title,
                menu: getMenuItems(action.title),
                ocupacoes: [],
                codOcupacoes: []
            }
        case actionTypes.FILTER_COURSE:
            return {
                ...state,
                listaCursosFiltrado: action.filtered
            }
        case actionTypes.SELECT_IES:
            // Acrescenta os dados do curso selecionado no Redux
            getIESIndicadores(
                {
                    anoSelecionado: state.anoSelecionado,
                    estadoSelecionado: state.estadoSelecionado,
                    municipioSelecionado: state.municipioSelecionado,
                    cursoSelecionado: state.cursoSelecionado,
                    instituicaoSelecionada: action.title
                }
            )
            return {
                ...state,
                instituicaoSelecionada: action.title
            }
        case actionTypes.FILTER_IES:
            return {
                ...state,
                listaInstituicoesFiltrado: action.filtered
            }
        case actionTypes.GET_LIST_COURSES:
            return {
                ...state,
                listaCursos: action.list
            }
        case actionTypes.GET_LIST_OCUPATIONS:
            return {
                ...state,
                listaOcupacoes: action.list
            }
        case actionTypes.FILTER_OCUPATION:
            return {
                ...state,
                listaOcupacoesFiltrado: action.filtered
            }
        case actionTypes.ADD_OCUPATION:
            const filterCondition = (value) => {
                return action.item !== value
            }

            const ocupacoesAdded = [
                ...state.ocupacoes,
                action.item
            ]

            const codOcupacoesAdded = [
                ...state.codOcupacoes,
                action.item.NU_CODIGO_CBO
            ]
            return {
                ...state,
                listaOcupacoes: state.listaOcupacoes.filter(filterCondition),
                listaOcupacoesFiltrado: state.listaOcupacoesFiltrado ? state.listaOcupacoesFiltrado.filter(filterCondition):false,
                ocupacoes: ocupacoesAdded,
                codOcupacoes: codOcupacoesAdded,
                menu: getMenuItems(state.cursoSelecionado, ocupacoesAdded),
                ocupacoesFiltrado: false
            }
        case actionTypes.FILTER_OCUPATION_ADDED:
            return {
                ...state,
                ocupacoesFiltrado: action.filtered
            }
        case actionTypes.REMOVE_OCUPATION:
            const removeCondition = (value) => {
                return action.item !== value
            }

            const removeCodCondition = (value) => {
                return action.item.NU_CODIGO_CBO !== value
            }
            
            const ocupacoesRemoved = state.ocupacoes.filter(removeCondition)
            const codOcupacoesRemoved = state.codOcupacoes.filter(removeCodCondition)
            return {
                ...state,
                ocupacoes: ocupacoesRemoved,
                codOcupacoes: codOcupacoesRemoved,
                ocupacoesFiltrado: state.ocupacoesFiltrado ? state.ocupacoesFiltrado.filter(removeCondition):false,
                listaOcupacoes: [
                    ...state.listaOcupacoes,
                    action.item
                ],
                menu: getMenuItems(state.cursoSelecionado, ocupacoesRemoved),
                listaOcupacoesFiltrado: false
            }
        case actionTypes.SAVE_OCUPATION:
            const newOcupacoesSaved = {
                ...state,
                ocupacoesSaved: state.ocupacoes
            }
            getIndicadores(newOcupacoesSaved)
            return newOcupacoesSaved
        case actionTypes.DISCARD_OCUPATION:
            return {
                ...state,
                ocupacoes: state.ocupacoesSaved
            }
        case actionTypes.CHANGE_YEAR:
            return {
                ...state,
                anoSelecionado: action.year
            }
        // Adiciona o estado selecionado ao Redux
        case actionTypes.SET_ESTADO_SELECIONADO:
            const newIndicadores = {
                ...state,
                estadoSelecionado: action.estado
            }
            getIndicadores(newIndicadores)
            return newIndicadores
        // Adiciona a lista de estados ao Redux
        case actionTypes.SET_MUNICIPIOS:
            return {
                ...state,
                listaMunicipios: action.list
            }
        case actionTypes.SET_INDICADORES:
            return {
                ...state,
                indicadores: action.list,
                loadingIndicadores: false
            }
        // Adiciona o município selecionado ao Redux
        case actionTypes.SET_MUNICIPIO_SELECIONADO:
            const newMunicipio = {
                ...state,
                municipioSelecionado: action.value
            }
            getIndicadores(newMunicipio)
            return newMunicipio
        case actionTypes.SET_LOADING:
            return {
                ...state,
                loadingIndicadores: action.loading
            }
        case actionTypes.SET_IES_LIST:
            return {
                ...state,
                listaInstituicoes: action.list
            }
        case actionTypes.SET_IES_INDICADORES:
            return {
                ...state,
                indicadoresIES: action.list,
                loadingIndicadores: false
            }
        case actionTypes.SAVE_COST:
            getIndicadoresROI({
                salarioMedio: state.indicadores.indicadorSalarioMedio.mediaOcupacao,
                salarioEnsinoMedio: state.indicadores.indicadorSalarioMedio.mediaEnsinoMedio,
                custo: action.cost.raw
            })
            return {
                ...state,
                custoTotal: action.cost
            }
        case actionTypes.SET_ROI:
            return {
                ...state,
                indicadoresROI: action.list
            }
        default:
            return state;
    }
};

export default reducer;